{
  "sentences": [
    {
      "text": "我在圖書館複習中文。",
      "pinyin": "Wǒ zài túshūguǎn fùxí zhōngwén.",
      "pinyin_numeric": "wo3 zai4 tu2shu1guan3 fu4xi2 zhong1wen2.",
      "translation_en": "I am reviewing Chinese at the library.",
      "translation_ko": "저는 도서관에서 중국어를 복습하고 있어요."
    },
    {
      "text": "他在公司改正錯誤。",
      "pinyin": "Tā zài gōngsī gǎizhèng cuòwù.",
      "pinyin_numeric": "ta1 zai4 gong1si1 gai3zheng4 cuo4wu4.",
      "translation_en": "He is correcting mistakes at the company.",
      "translation_ko": "그는 회사에서 실수를 고치고 있어요."
    },
    {
      "text": "我們在教室寫句子。",
      "pinyin": "Wǒmen zài jiàoshì xiě jùzi.",
      "pinyin_numeric": "wo3men5 zai4 jiao4shi4 xie3 ju4zi5.",
      "translation_en": "We are writing sentences in the classroom.",
      "translation_ko": "우리는 교실에서 문장을 쓰고 있어요."
    },
    {
      "text": "她在公園說中文，很流利。",
      "pinyin": "Tā zài gōngyuán shuō zhōngwén, hěn liúlì.",
      "pinyin_numeric": "ta1 zai4 gong1yuan2 shuo1 zhong1wen2, hen3 liu2li4.",
      "translation_en": "She speaks Chinese fluently in the park.",
      "translation_ko": "그녀는 공원에서 중국어를 유창하게 말해요."
    },
    {
      "text": "我在家裡複習重點。",
      "pinyin": "Wǒ zài jiā lǐ fùxí zhòngdiǎn.",
      "pinyin_numeric": "wo3 zai4 jia1 li3 fu4xi2 zhong4dian3.",
      "translation_en": "I am reviewing the key points at home.",
      "translation_ko": "저는 집에서 중요한 점을 복습하고 있어요."
    },
    {
      "text": "他在咖啡店改正弱點。",
      "pinyin": "Tā zài kāfēidiàn gǎizhèng ruòdiǎn.",
      "pinyin_numeric": "ta1 zai4 ka1fei1dian4 gai3zheng4 ruo4dian3.",
      "translation_en": "He is correcting his weaknesses at the coffee shop.",
      "translation_ko": "그는 커피숍에서 약점을 고치고 있어요."
    },
    {
      "text": "我們在學校再試一次。",
      "pinyin": "Wǒmen zài xuéxiào zài shì yī cì.",
      "pinyin_numeric": "wo3men5 zai4 xue2xiao4 zai4 shi4 yi1 ci4.",
      "translation_en": "We are trying again at school.",
      "translation_ko": "우리는 학교에서 다시 한 번 시도하고 있어요."
    },
    {
      "text": "她在餐廳說答案，很清楚。",
      "pinyin": "Tā zài cāntīng shuō dá'àn, hěn qīngchǔ.",
      "pinyin_numeric": "ta1 zai4 can1ting1 shuo1 da2'an4, hen3 qing1chu3.",
      "translation_en": "She says the answer clearly at the restaurant.",
      "translation_ko": "그녀는 식당에서 답을 아주 명확하게 말해요."
    },
    {
      "text": "我在捷運站複習句子。",
      "pinyin": "Wǒ zài jiéyùnzhàn fùxí jùzi.",
      "pinyin_numeric": "wo3 zai4 jie2yun4zhan4 fu4xi2 ju4zi5.",
      "translation_en": "I am reviewing sentences at the MRT station.",
      "translation_ko": "저는 지하철역에서 문장을 복습하고 있어요."
    },
    {
      "text": "他在醫院改正錯誤，再試一次。",
      "pinyin": "Tā zài yīyuàn gǎizhèng cuòwù, zài shì yī cì.",
      "pinyin_numeric": "ta1 zai4 yi1yuan4 gai3zheng4 cuo4wu4, zai4 shi4 yi1 ci4.",
      "translation_en": "He corrects mistakes at the hospital and tries again.",
      "translation_ko": "그는 병원에서 실수를 고치고 다시 한 번 시도해요."
    }
  ]
}
